/**
 * kbHelpers.js — Shared utilities for the Knowledge Base feature.
 *
 * Extracted from KnowledgeBasePage.jsx as part of R4 refactoring.
 * All exports are named exports (no default).
 */

// ── Available tags ────────────────────────────────────────────────────────────

